  }, []);

  const load = useCallback(async (isRefresh: boolean) => {
    if (isRefresh) setRefreshing(true);
    else setLoading(true);
    setError(null);

    const { data, error: rpcError } = await supabase.rpc('list_discover_feed', {
      p_eligible_only: eligibleRef.current,
